import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def extract(data):
    pkgs = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                pkgs[(name, pkg['id'])] = pkg['resolvedVersion']
    return pkgs

b, a = extract(baseline), extract(after)
changes = [(k,b[k],a[k]) for k in b if b[k] != a.get(k)]
added = [(k,a[k]) for k in a if k not in b]
removed = [(k,b[k]) for k in b if k not in a]
if not changes and not added and not removed:
    print('✅ Conversion is fully version-neutral. All packages resolve identically.')
else:
    for c in changes: print(f'CHANGED: {c}')
    for c in added: print(f'ADDED: {c}')
    for c in removed: print(f'REMOVED: {c}')
"

